code = """import json
import pandas as pd

# Load Opportunity Close Dates
opp_dates = locals()['var_function-call-15022579308412071662']

df = pd.DataFrame(opp_dates)
df['CloseDate'] = pd.to_datetime(df['CloseDate'])

# Filter for past 10 months from 2021-04-10
end_date = pd.Timestamp('2021-04-10')
start_date = end_date - pd.DateOffset(months=10)

df_filtered = df[(df['CloseDate'] >= start_date) & (df['CloseDate'] <= end_date)]

# Group by month
df_filtered['MonthName'] = df_filtered['CloseDate'].dt.month_name()
df_filtered['Year'] = df_filtered['CloseDate'].dt.year
monthly_counts = df_filtered.groupby(['Year', 'MonthName']).size().reset_index(name='count')
monthly_counts = monthly_counts.sort_values(by='count', ascending=False)

print("__RESULT__:")
print(monthly_counts.to_json(orient='records'))"""

